              <ArrowLeft className="size-4" />
              Quay lại đăng nhập
            </Link>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

src/components/admin-data-table/admin-da.content:
"use client";

import {
  flexRender,
  getCoreRowModel,
  getExpandedRowModel,
  getFilteredRowModel,
  getSortedRowModel,
  useReactTable,
  type ColumnDef,
  type ColumnFiltersState,
  type ExpandedState,
  type Header,
  type OnChangeFn,
  type Row,
  type SortingState,
} from "@tanstack/react-table";
import { ChevronDown, ChevronRight, Download } from "lucide-react";
import { useCallback, useMemo, useState, type ReactNode } from "react";
import { Button } from "@ui/components/button";
import { Input } from "@ui/components/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@ui/components/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@ui/components/table";
import { cn } from "@ui/lib/utils";
import "@/components/admin-data-table/table-meta";
import { buildCsvFromColumns } from "@/lib/build-table-csv";
import { downloadCsvFile } from "@/lib/export-csv";
import {
  csvBaseToXlsxFilename,
  downloadXlsxFile,
} from "@/lib/export-xlsx";

const ALL_SELECT = "__all__";

export type AdminDataTableProps<TData> = {
  data: TData[];
  columns: ColumnDef<TData, unknown>[];
  getSubRows?: (row: TData) => TData[] | undefined;
  isLoading?: boolean;
  emptyLabel?: string;
  /** Mở toàn bộ nhánh cây lúc đầu */
  defaultExpandedAll?: boolean;
  getRowClassName?: (row: Row<TData>) => string | undefined;
  /** Ô tìm nhanh (chuỗi do bạn cung cấp cho mỗi dòng) */
  getGlobalFilterText?: (row: TData) => string;
  globalFilterPlaceholder?: string;
  /** Bật khi lọc do API/server — chỉ giữ state ô lọc, không lọc lại `data` trên client */
  manualFiltering?: boolean;
  columnFilters?: ColumnFiltersState;
  onColumnFiltersChange?: OnChangeFn<ColumnFiltersState>;
  globalFilter?: string;
  onGlobalFilterChange?: OnChangeFn<string>;
  /** Nút / nhóm tùy chọn cạnh ô tìm nhanh (vd. “Xóa bộ lọc”) */
  filterToolbarExtra?: ReactNode;
  /** Phân trang / tóm tắt ngay dưới bảng */
  footer?: ReactNode;
  /**
   * Hiện nút xuất CSV + Excel (dữ liệu đúng mảng `data` hiện tại — thường là một trang/lớp đã lọc).
   */
  csvExport?: boolean | { fileName?: string; sheetName?: string };
};

function includesText(a: unknown, q: string): boolean {
  if (!q) return true;
  const s = String(a ?? "").toLowerCase();
  return s.includes(q.toLowerCase());
}

function columnFilterToolbarLabel<TData>(
  header: Header<TData, unknown>,
): string {
  const meta = header.column.columnDef.meta;
  if (meta?.filterLabel) return meta.filterLabel;
  const h = header.column.columnDef.header;
  if (typeof h === "string") return h;
  return header.column.id;
}

export function AdminDataTable<TData>({
  data,
  columns,
  getSubRows,
  isLoading,
  emptyLabel = "Không có dữ liệu",
  defaultExpandedAll = true,
  getRowClassName,
  getGlobalFilterText,
  globalFilterPlaceholder = "Tìm trong bảng…",
  manualFiltering = false,
  columnFilters: columnFiltersControlled,
  onColumnFiltersChange,
  globalFilter: globalFilterControlled,
  onGlobalFilterChange,
  filterToolbarExtra,
  footer,
  csvExport,
}: AdminDataTableProps<TData>) {
  const [sorting, setSorting] = useState<SortingState>([]);
  const [columnFiltersInternal, setColumnFiltersInternal] =
    useState<ColumnFiltersState>([]);
  const [globalFilterInternal, setGlobalFilterInternal] = useState("");
  const columnFilters = columnFiltersControlled ?? columnFiltersInternal;
  const setColumnFilters =
    onColumnFiltersChange ?? setColumnFiltersInternal;
  const globalFilter = globalFilterControlled ?? globalFilterInternal;
  const setGlobalFilter = onGlobalFilterChange ?? setGlobalFilterInternal;
  const showGlobalFilter =
    getGlobalFilterText != null || onGlobalFilterChange != null;
  const csvExportEnabled = Boolean(csvExport);
  const exportFileNameProp =
    typeof csvExport === "object" && csvExport != null
      ? csvExport.fileName?.trim()
      : undefined;
  const exportSheetNameProp =
    typeof csvExport === "object" && csvExport != null
      ? csvExport.sheetName?.trim()
      : undefined;
  const resolvedCsvFileName = useMemo(() => {
    if (exportFileNameProp) {
      return exportFileNameProp.toLowerCase().endsWith(".csv")
        ? exportFileNameProp
        : `${exportFileNameProp}.csv`;
    }
    return `xuat-bang-${new Date().toISOString().slice(0, 10)}.csv`;
  }, [exportFileNameProp]);
  const resolvedXlsxFileName = useMemo(
    () => csvBaseToXlsxFilename(resolvedCsvFileName),
    [resolvedCsvFileName],
  );

  const handleCsvExport = useCallback(() => {
    const { headers, rows } = buildCsvFromColumns(data, columns);
    downloadCsvFile(resolvedCsvFileName, headers, rows);
  }, [columns, data, resolvedCsvFileName]);

  const handleXlsxExport = useCallback(() => {
    const { headers, rows } = buildCsvFromColumns(data, columns);
    void downloadXlsxFile(
      resolvedXlsxFileName,
      headers,
      rows,
      exportSheetNameProp || "Dữ liệu",
    );
  }, [columns, data, exportSheetNameProp, resolvedXlsxFileName]);
  const [expanded, setExpanded] = useState<ExpandedState>(
    defaultExpandedAll ? true : {},
  );

  const expanderColumn = useMemo<ColumnDef<TData, unknown>>(
    () => ({
      id: "_expand",
      header: () => null,
      cell: ({ row }) => {
        if (!row.getCanExpand()) {
          return <span className="inline-block w-8 shrink-0" aria-hidden />;
        }
        return (
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="h-8 w-8 shrink-0"
            aria-expanded={row.getIsExpanded()}
            aria-label={row.getIsExpanded() ? "Thu gọn" : "Mở rộng"}
            onClick={(e) => {
              e.stopPropagation();
              row.getToggleExpandedHandler()();
            }}
          >
            {row.getIsExpanded() ? (
              <ChevronDown className="size-4" />
            ) : (
              <ChevronRight className="size-4" />
            )}
          </Button>
        );
      },
      enableSorting: false,
      enableColumnFilter: false,
      meta: { disableColumnFilter: true },
      size: 44,
    }),
    [],
  );

  const tableColumns = useMemo(
    () => (getSubRows ? [expanderColumn, ...columns] : columns),
    [columns, expanderColumn, getSubRows],
  );

  const table = useReactTable({
    data,
    columns: tableColumns,
    state: { sorting, columnFilters, globalFilter, expanded },
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onGlobalFilterChange: setGlobalFilter,
    onExpandedChange: setExpanded,
    getSubRows,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getExpandedRowModel: getExpandedRowModel(),
    manualFiltering,
    // false: lọc từ dòng cha xuống (đúng cho cây SP→đơn vị). true + filterFn “luôn pass” ở lá
    // khiến cha luôn được giữ vì còn lá con → lọc cột như không chạy.
    filterFromLeafRows: false,
    globalFilterFn: manualFiltering
      ? "includesString"
      : getGlobalFilterText
        ? (row, _columnId, filterValue) => {
            const q = String(filterValue ?? "").trim();
            if (!q) return true;
            return includesText(getGlobalFilterText(row.original), q);
          }
        : "includesString",
    autoResetExpanded: false,
    defaultColumn: {
      enableColumnFilter: true,
      filterFn: (row, columnId, filterValue) => {
        if (filterValue == null || filterValue === "") return true;
        return includesText(row.getValue(columnId), String(filterValue));
      },
    },
  });

  const headerGroups = table.getHeaderGroups();
  const rows = table.getRowModel().rows;

  const filterableHeaders = table
    .getFlatHeaders()
    .filter(
      (h) =>
        h.column.getCanFilter() &&
        !h.column.columnDef.meta?.disableColumnFilter,
    );

  function renderOutsideColumnFilter(header: Header<TData, unknown>) {
    const col = header.column;
    const controlId = `admin-col-filter-ctl-${header.id}`;
    const meta = col.columnDef.meta;
    const variant = meta?.filterVariant ?? "text";
    const ph = meta?.filterPlaceholder ?? "Lọc…";

    if (variant === "select" && meta?.selectOptions?.length) {
      const opts = meta.selectOptions;
      const v = (col.getFilterValue() as string) ?? ALL_SELECT;
      return (
        <Select
          value={v === "" || v == null ? ALL_SELECT : v}
          onValueChange={(next) =>
            col.setFilterValue(next === ALL_SELECT ? undefined : next)
          }
        >
          <SelectTrigger
            id={controlId}
            className="h-9 text-sm rounded-lg w-full min-w-[160px]"
          >
            <SelectValue placeholder="Tất cả">
              {v === ALL_SELECT ? "Tất cả" : undefined}
            </SelectValue>
          </SelectTrigger>
          <SelectContent className="max-h-[min(60vh,22rem)] overflow-y-auto">
            <SelectItem value={ALL_SELECT}>Tất cả</SelectItem>
            {opts.map((o) => (
              <SelectItem key={o.value} value={o.value}>
                {o.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      );
    }

    if (variant === "number") {
      return (
        <Input
          id={controlId}
          type="number"
          className="h-9 text-sm rounded-lg"
          placeholder={ph}
          value={(col.getFilterValue() as string) ?? ""}
          onChange={(e) =>
            col.setFilterValue(
              e.target.value === "" ? undefined : Number(e.target.value),
            )
          }
        />
      );
    }

    return (
      <Input
        id={controlId}
        className="h-9 text-sm rounded-lg"
        placeholder={ph}
        value={(col.getFilterValue() as string) ?? ""}
        onChange={(e) =>
          col.setFilterValue(e.target.value === "" ? undefined : e.target.value)
        }
      />
    );
  }

  if (isLoading) {
    return (
      <div className="space-y-2 rounded-xl border border-border bg-card p-4">
        {Array.from({ length: 6 }).map((_, i) => (
          <div
            key={i}
            className="h-10 rounded-md bg-muted/40 animate-pulse"
          />
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {(showGlobalFilter ||
        filterableHeaders.length > 0 ||
        filterToolbarExtra ||
        csvExportEnabled) && (
        <div className="rounded-lg border border-border bg-card p-3 sm:p-4 space-y-4">
          {showGlobalFilter || filterToolbarExtra || csvExportEnabled ? (
            <div className="flex flex-wrap items-end gap-3">
              {showGlobalFilter ? (
                <div className="flex min-w-[min(100%,18rem)] flex-1 flex-col gap-1.5">
                  <label className="text-xs font-semibold text-muted-foreground">
                    Tìm nhanh
                  </label>
                  <Input
                    placeholder={globalFilterPlaceholder}
                    value={globalFilter}
                    onChange={(e) => setGlobalFilter(e.target.value)}
                    className="bg-background rounded-lg w-full"
                  />
                </div>
              ) : null}
              <div className="flex flex-wrap items-end gap-2 shrink-0">
                {csvExportEnabled ? (
                  <div className="flex flex-col gap-1.5">
                    <span className="text-xs font-semibold text-muted-foreground">
                      Xuất file
                    </span>
                    <div className="flex flex-wrap gap-2">
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-9 gap-1.5 rounded-lg"
                        disabled={data.length === 0}
                        onClick={handleCsvExport}
                        title="CSV: cột phân tách bằng ; + UTF-16 LE (Excel VN)"
                      >
                        <Download className="size-4" />
                        CSV
                      </Button>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-9 gap-1.5 rounded-lg"
                        disabled={data.length === 0}
                        onClick={handleXlsxExport}
                        title="Excel: cột rộng theo nội dung, Unicode chuẩn"
                      >
                        <Download className="size-4" />
                        Excel
                      </Button>
                    </div>
                  </div>
                ) : null}
                {filterToolbarExtra ? (
                  <div className="flex flex-wrap gap-2">{filterToolbarExtra}</div>
                ) : null}
              </div>
            </div>
          ) : null}
          {filterableHeaders.length > 0 && (
            <div className="space-y-2">
              <p className="text-xs font-semibold text-muted-foreground">
                Lọc theo cột
              </p>
              <div className="flex flex-wrap gap-x-4 gap-y-3 items-end">
                {filterableHeaders.map((header) => (
                  <div
                    key={header.id}
                    className="flex flex-col gap-1 min-w-[min(100%,12rem)] w-[12rem]"
                  >
                    <label
                      htmlFor={`admin-col-filter-ctl-${header.id}`}
                      className="text-xs font-medium text-foreground/80"
                    >
                      {columnFilterToolbarLabel(header)}
                    </label>
                    <div>{renderOutsideColumnFilter(header)}</div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      <div className="rounded-lg border border-border bg-card overflow-hidden">
        <div className="overflow-x-auto py-3 sm:py-4">
        <Table className="text-sm min-w-[640px] sm:min-w-0">
          <TableHeader>
            {headerGroups.map((hg) => (
              <TableRow key={hg.id} className="hover:bg-transparent">
                {hg.headers.map((header) => (
                  <TableHead
                    key={header.id}
                    className={cn(
                      "align-top font-semibold whitespace-normal",
                      header.column.getCanSort() && "cursor-pointer select-none",
                    )}
                    onClick={header.column.getToggleSortingHandler()}
                  >
                    {header.isPlaceholder ? null : (
                      <div className="flex flex-col gap-1 py-1">
                        <span className="flex items-center gap-1">
                          {flexRender(
                            header.column.columnDef.header,
                            header.getContext(),
                          )}
                          {header.column.getIsSorted() === "asc"
                            ? " ↑"
                            : header.column.getIsSorted() === "desc"
                              ? " ↓"
                              : null}
                        </span>
                      </div>
                    )}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {rows.length === 0 ? (
              <TableRow>
                <TableCell
                  colSpan={tableColumns.length}
                  className="h-24 text-center text-muted-foreground"
                >
                  {emptyLabel}
                </TableCell>
              </TableRow>
            ) : (
              rows.map((row) => (
                <TableRow
                  key={row.id}
                  data-depth={row.depth}
                  className={cn(
                    row.depth > 0 && "bg-muted/15",
                    getRowClassName?.(row),
                  )}
                >
                  {row.getVisibleCells().map((cell) => {
                    const colIndex = cell.column.getIndex();
                    const indent =
                      getSubRows && colIndex === 1 ? row.depth * 14 : 0;
                    return (
                      <TableCell
                        key={cell.id}
                        className="whitespace-normal align-middle max-w-[min(420px,40vw)]"
                        style={{
                          paddingLeft:
                            indent > 0
                              ? `calc(0.5rem + ${indent}px)`
                              : undefined,
                        }}
                      >
                        {flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext(),
                        )}
                      </TableCell>
                    );
                  })}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
        </div>
      </div>
      {footer ? (
        <div className="flex flex-wrap items-center justify-between gap-3 rounded-lg border border-border bg-card px-3 py-3 sm:px-4">
          {footer}
        </div>
      ) : null}
    </div>
  );
}

src/components/admin-data-table/table-me.content:
import type { RowData } from "@tanstack/react-table";

declare module "@tanstack/react-table" {
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  interface ColumnMeta<TData extends RowData, TValue> {
    filterVariant?: "text" | "select" | "number";
    filterPlaceholder?: string;
    /** Nhãn ô lọc ngoài bảng (mặc định: header cột) */
    filterLabel?: string;
    selectOptions?: { value: string; label: string }[];
    /** Không hiển thị ô lọc dưới header (vd. cột nút) */
    disableColumnFilter?: boolean;
    /** Bỏ qua khi xuất CSV (cột thao tác, icon, …) */
    excludeFromExport?: boolean;
  }
}

export {};

src/components/admin-shell.tsx.content:
"use client";

import { useEffect, useRef, useState, type ReactNode } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { Bell, Menu, PanelLeftClose, PanelLeft } from "lucide-react";
import { Button } from "@ui/components/button";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from "@ui/components/sheet";
import { MobileSidebarPanel, Sidebar } from "@/components/sidebar";
import { TextSizeToggle } from "@ui/components/text-size-toggle";
import { canAccessStaffAdmin } from "@workspace/api-client";
import { useAuth, useClientReady } from "@/providers/auth-provider";
import {
  ADMIN_SESSION_EVENT,
  clearAdminSession,
} from "@/lib/auth-session";
import { isAuthPath } from "@/lib/auth-routes";

const SIDEBAR_COLLAPSED_KEY = "admin-sidebar-collapsed";

function initials(fullName: string): string {
  const p = fullName.trim().split(/\s+/).filter(Boolean);
  if (p.length === 0) return "?";
  if (p.length === 1) return p[0].slice(0, 2).toUpperCase();
  return (p[0][0] + p[p.length - 1][0]).toUpperCase();
}

function roleSummary(user: { roles: { code: string; name: string }[] }): string {
  if (!user.roles.length) return "Chưa gán vai trò";
  return user.roles.map((r) => r.name).join(" · ");
}

function AuthLoadingScreen({ message }: { message: string }) {
  return (
    <div className="min-h-screen flex items-center justify-center bg-muted/30 text-muted-foreground text-sm">
      {message}
    </div>
  );
}

export function AdminShell({ children }: { children: ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const clientReady = useClientReady();
  const { user } = useAuth();
  const onAuthRoute = isAuthPath(pathname);
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [mobileNavOpen, setMobileNavOpen] = useState(false);
  const skipSidebarPersist = useRef(true);

  useEffect(() => {
    try {
      setSidebarCollapsed(localStorage.getItem(SIDEBAR_COLLAPSED_KEY) === "1");
    } catch {
      /* ignore */
    }
  }, []);

  useEffect(() => {
    if (skipSidebarPersist.current) {
      skipSidebarPersist.current = false;
      return;
    }
    try {
      localStorage.setItem(SIDEBAR_COLLAPSED_KEY, sidebarCollapsed ? "1" : "0");
    } catch {
      /* ignore */
    }
  }, [sidebarCollapsed]);

  useEffect(() => {
    if (!clientReady) return;

    if (onAuthRoute) {
      if (user && canAccessStaffAdmin(user)) {
        router.replace("/");
        return;
      }
      if (user && !canAccessStaffAdmin(user)) {
        clearAdminSession();
        window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
        router.replace("/login?reason=staff_only");
      }
      return;
    }

    if (!user) {
      router.replace("/login");
      return;
    }
    if (!canAccessStaffAdmin(user)) {
      clearAdminSession();
      window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
      router.replace("/login?reason=staff_only");
    }
  }, [clientReady, onAuthRoute, user, router]);

  if (onAuthRoute) {
    if (!clientReady) {
      return <AuthLoadingScreen message="Đang tải…" />;
    }
    if (user && canAccessStaffAdmin(user)) {
      return <AuthLoadingScreen message="Đang chuyển về bảng điều khiển…" />;
    }
    return <>{children}</>;
  }

  if (!clientReady || !user) {
    return <AuthLoadingScreen message="Đang tải…" />;
  }

  return (
    <div className="flex min-h-screen w-full flex-col bg-background font-sans text-foreground md:flex-row">
      <Sheet open={mobileNavOpen} onOpenChange={setMobileNavOpen}>
        <SheetContent
          side="left"
          showCloseButton
          className="flex w-[min(100vw,20rem)] flex-col border-sidebar-border bg-sidebar p-0 text-sidebar-foreground sm:max-w-sm"
        >
          <SheetHeader className="sr-only">
            <SheetTitle>Menu điều hướng</SheetTitle>
          </SheetHeader>
          <MobileSidebarPanel onNavigate={() => setMobileNavOpen(false)} />
        </SheetContent>
      </Sheet>

      <Sidebar
        collapsed={sidebarCollapsed}
        onToggleCollapsed={() => setSidebarCollapsed((c) => !c)}
      />

      <div className="flex min-w-0 flex-1 flex-col">
        <header className="sticky top-0 z-10 flex h-14 shrink-0 items-center justify-between border-b border-border bg-surface/80 px-3 backdrop-blur-sm sm:h-16 sm:px-6">
          <div className="flex min-w-0 items-center gap-1 sm:gap-2">
            <Button
              type="button"
              variant="ghost"
              size="icon"
              className="shrink-0 rounded-lg text-muted-foreground hover:text-primary md:hidden"
              onClick={() => setMobileNavOpen(true)}
              aria-label="Mở menu điều hướng"
            >
              <Menu className="size-6" />
            </Button>
            <h2 className="shrink-0 truncate text-lg font-bold text-primary sm:text-xl md:hidden">
              B2B Admin
            </h2>
            <Button
              type="button"
              variant="ghost"
              size="icon"
              className="hidden shrink-0 rounded-lg text-muted-foreground hover:text-primary md:inline-flex"
              onClick={() => setSidebarCollapsed((c) => !c)}
              aria-label={sidebarCollapsed ? "Mở sidebar" : "Thu gọn sidebar"}
              title={sidebarCollapsed ? "Mở sidebar" : "Thu gọn sidebar"}
            >
              {sidebarCollapsed ? (
                <PanelLeft className="size-5" />
              ) : (
                <PanelLeftClose className="size-5" />
              )}
            </Button>
          </div>
          <div className="flex-1" />
          <div className="flex items-center gap-2 sm:gap-4">
            <TextSizeToggle />
            <Button
              variant="ghost"
              size="icon"
              className="text-muted-foreground hover:text-primary"
              type="button"
            >
              <Bell className="size-5" />
            </Button>
            <Link
              href="/profile"
              className="flex items-center gap-3 pl-4 border-l border-border/50 rounded-lg pr-1 py-1 -my-1 hover:bg-muted/60 transition-colors"
              title="Hồ sơ & tài khoản"
            >
              <div className="text-right hidden sm:block">
                <p className="text-sm font-bold leading-none">{user.fullName}</p>
                <p
                  className="text-xs text-muted-foreground mt-1 max-w-[220px] truncate"
                  title={roleSummary(user)}
                >
                  {roleSummary(user)}
                </p>
              </div>
              <div className="w-10 h-10 bg-primary/10 rounded-full flex items-center justify-center text-primary font-bold border border-primary/20 text-sm">
                {initials(user.fullName)}
              </div>
            </Link>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto bg-muted/20 p-4 sm:p-6">
          {children}
        </main>
      </div>
    </div>
  );
}

src/components/admin-table-pagination-fo.content:
"use client";

import { useMemo } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@ui/components/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@ui/components/select";

/** Mức page size dùng chung (API thường giới hạn ≤ 200). */
export const ADMIN_TABLE_PAGE_SIZE_OPTIONS = [10, 15, 20, 25, 50] as const;

export type AdminTablePaginationFooterProps = {
  page: number;
  pageSize: number;
  total: number;
  isLoading?: boolean;
  onPageChange: (page: number) => void;
  /** Parent nên `setPage(1)` khi đổi limit (vd. `useEffect` phụ thuộc `pageSize`). */
  onPageSizeChange: (pageSize: number) => void;
  pageSizeOptions?: readonly number[];
  emptySummary: string;
  /** VD: `đơn` → `Hiển thị 1–20 / 100 đơn`; bỏ trống chỉ hiện `… / 100`. */
  itemLabel?: string;
};

export function AdminTablePaginationFooter({
  page,
  pageSize,
  total,
  isLoading = false,
  onPageChange,
  onPageSizeChange,
  pageSizeOptions = ADMIN_TABLE_PAGE_SIZE_OPTIONS,
  emptySummary,
  itemLabel,
}: AdminTablePaginationFooterProps) {
  const totalPages = Math.max(1, Math.ceil(total / pageSize));
  const from = total === 0 ? 0 : (page - 1) * pageSize + 1;
  const to = Math.min(page * pageSize, total);

  const summary =
    total === 0
      ? emptySummary
      : itemLabel
        ? `Hiển thị ${from}–${to} / ${total} ${itemLabel}`
        : `Hiển thị ${from}–${to} / ${total}`;

  const sizeChoices = useMemo(() => {
    const set = new Set<number>([...pageSizeOptions, pageSize]);
    return [...set].sort((a, b) => a - b);
  }, [pageSize, pageSizeOptions]);

  return (
    <>
      <p className="text-sm text-muted-foreground">{summary}</p>
      <div className="flex flex-wrap items-center justify-end gap-2 sm:gap-3">
        <div className="flex items-center gap-2">
          <span className="text-xs font-medium text-muted-foreground whitespace-nowrap">
            Mỗi trang
          </span>
          <Select
            value={String(pageSize)}
            onValueChange={(v) => onPageSizeChange(Number(v))}
            disabled={isLoading}
          >
            <SelectTrigger className="h-9 w-[4.75rem] rounded-lg text-sm tabular-nums">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {sizeChoices.map((n) => (
                <SelectItem key={n} value={String(n)}>
                  {n}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="flex items-center gap-2">
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-9 rounded-lg"
            disabled={page <= 1 || isLoading}
            onClick={() => onPageChange(Math.max(1, page - 1))}
          >
            <ChevronLeft className="size-4" />
            Trước
          </Button>
          <span className="px-1 text-sm tabular-nums text-muted-foreground sm:px-2">
            Trang {page} / {totalPages}
          </span>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-9 rounded-lg"
            disabled={page >= totalPages || isLoading}
            onClick={() => onPageChange(Math.min(totalPages, page + 1))}
          >
            Sau
            <ChevronRight className="size-4" />
          </Button>
        </div>
      </div>
    </>
  );
}

src/components/sidebar.tsx.content:
"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import {
  ShieldCheck,
  Database,
  LayoutDashboard,
  ListTodo,
  Package,
  Store,
  Tags,
  TicketPercent,
  LogOut,
  ChevronsLeft,
  ChevronsRight,
  Users,
} from "lucide-react";
import { cn } from "@ui/lib/utils";
import {
  canUserAccess,
  PERMISSION_CODES,
  type PermissionCode,
} from "@workspace/api-client";
import { useAuth } from "@/providers/auth-provider";
import type { AuthUser } from "@/lib/api";

type MenuItem = {
  href: string;
  label: string;
  icon: typeof LayoutDashboard;
  /** `null` = không kiểm tra một mã đơn lẻ (dùng kèm {@link anyPermission} hoặc mở cho mọi user). */
  permission: PermissionCode | null;
  /** Nếu có: user cần ít nhất một quyền trong danh sách (ưu tiên hơn `permission`). */
  anyPermission?: PermissionCode[];
};

const menuItems: MenuItem[] = [
  { href: "/", label: "Tổng quan", icon: LayoutDashboard, permission: null },
  {
    href: "/staff",
    label: "Nhân sự & phân quyền",
    icon: Users,
    permission: null,
    anyPermission: [
      PERMISSION_CODES.USERS_MANAGE,
      PERMISSION_CODES.RBAC_READ,
    ],
  },
  {
    href: "/orders",
    label: "Quản lý Đơn hàng",
